import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #e6f4ea, #ffffff)',
      padding: 20
    }}>
      <div style={{ width: '100%', maxWidth: 420 }}>

        {/* HEADER */}
        <div style={{ textAlign: 'center', marginBottom: 30 }}>
          <h1 style={{
            fontSize: 34,
            fontWeight: '700',
            background: 'linear-gradient(90deg, #16a34a, #22c55e)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent'
          }}>
            ⚡ TeamTask
          </h1>

          <p style={{ color: '#6b7280', marginTop: 6 }}>
            Smart Team Management System
          </p>
        </div>

        {/* CARD */}
        <div style={{
          background: '#fff',
          padding: 30,
          borderRadius: 16,
          boxShadow: '0 10px 30px rgba(0,0,0,0.08)',
          border: '1px solid #e5e7eb'
        }}>
          <h2 style={{
            textAlign: 'center',
            marginBottom: 20,
            fontWeight: '600'
          }}>
            Welcome Back 👋
          </h2>

          <form onSubmit={handleSubmit}>

            {/* EMAIL */}
            <div style={{ marginBottom: 15 }}>
              <label style={{ fontSize: 13, fontWeight: 500 }}>Email</label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '12px 14px',
                  marginTop: 6,
                  borderRadius: 10,
                  border: '1px solid #d1d5db',
                  outline: 'none',
                  fontSize: 14
                }}
              />
            </div>

            {/* PASSWORD */}
            <div style={{ marginBottom: 20 }}>
              <label style={{ fontSize: 13, fontWeight: 500 }}>Password</label>
              <input
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '12px 14px',
                  marginTop: 6,
                  borderRadius: 10,
                  border: '1px solid #d1d5db',
                  outline: 'none',
                  fontSize: 14
                }}
              />
            </div>

            {/* BUTTON */}
            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%',
                padding: '12px',
                borderRadius: 10,
                border: 'none',
                background: 'linear-gradient(90deg, #16a34a, #22c55e)',
                color: '#fff',
                fontWeight: '600',
                fontSize: 15,
                cursor: 'pointer',
                transition: '0.3s'
              }}
            >
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>

          </form>

          {/* FOOTER */}
          <p style={{
            textAlign: 'center',
            marginTop: 18,
            fontSize: 13,
            color: '#6b7280'
          }}>
            No account? <Link to="/register" style={{ color: '#16a34a', fontWeight: 600 }}>Register</Link>
          </p>
        </div>

        {/* INFO BOX */}
        <div style={{
          marginTop: 20,
          padding: 15,
          background: '#ecfdf5',
          borderRadius: 10,
          border: '1px solid #bbf7d0'
        }}>
          <p style={{ fontSize: 12, color: '#065f46' }}>
            💡 Use <b>admin</b> to create tasks & <b>member</b> to submit tasks
          </p>
        </div>

      </div>
    </div>
  );
}
